<script>
	// Line comment between else and non-block body - block consequent
	if(a){expr;}else// c1
	expr;

	// Line comment between else and non-block body - comments path
	if(a){expr;}// between
	else// c1
	expr;

	// Line comment between else and non-block body - non-block consequent
	if(a)expr;else// c1
	expr;
</script>
